use std::collections::HashMap;
use std::sync::Mutex;

struct UrlShortener {
    storage: Mutex<HashMap<String, String>>,
}

impl UrlShortener {
    fn new() -> Self {
        UrlShortener {
            storage: Mutex::new(HashMap::new()),
        }
    }

    fn get_short_code(&self, original_url: &str) -> Option<String> {
        let mut map = self.storage.lock().unwrap();
        if let Some(short_key) = map.get(original_url) {
            return Some(short_key.clone());
        }
        None
    }

    fn create_mapping(&self, original_url: &str, short_key: String) -> bool {
        let mut map = self.storage.lock().unwrap();
        if map.contains_key(original_url) {
            return false;
        }
        map.insert(original_url.to_owned(), short_key);
        true
    }
}

fn main() {
    let service = UrlShortener::new();
    let url1 = "https://verylongdomainname.com/page/id=123";
    let key1 = "abcde";

    if service.create_mapping(url1, key1.to_string()) {
        println!("Stored mapping for: {}", url1);
    }

    match service.get_short_code(url1) {
        Some(key) => println!("Found existing short code: {}", key),
        None => println!("Should not happen if stored correctly.")
    }

    let url2 = "https://anotherdomain.org/test";
    if service.create_mapping(url2, "xyz78".to_string()) {
        println!("Stored mapping for: {}", url2);
    }

    // Attempting to overwrite should fail gracefully
    let success = service.create_mapping(url1, "newkey".to_string());
    if !success {
        println!("Successfully prevented overwriting existing entry for: {}", url1);
    }
}

use std::collections::HashMap;
use std::time::{Duration, Instant};

struct LogMonitor {
    cache: HashMap<String, String>,
}

impl LogMonitor {
    fn new() -> Self {
        LogMonitor { cache: HashMap::new() }
    }

    fn process_record(&mut self, cert_name: &str, data: &str) -> String {
        if let Some(result) = self.cache.get(cert_name) {
            println!("Cache hit for {}", cert_name);
            return result.clone();
        }

        println!("Cache miss for {}. Performing expensive calculation...", cert_name);
        let calculated_result = self.calculate_expensive_check(cert_name, data);

        self.cache.insert(String::from(cert_name.to_uppercase()), calculated_result.clone());
        calculated_result
    }

    fn calculate_expensive_check(&self, cert_name: &str, data: &str) -> String {
        let start = Instant::now();
        std::thread::sleep(Duration::from_millis(50));
        format!("Processed successfully in {:?}", start.elapsed()) 
    }
}

fn main() {
    let mut monitor = LogMonitor::new();

    let cert1 = "example.com";
    let data1 = "data_payload_a";

    println!("--- First Run ---");
    let result1 = monitor.process_record(cert1, data1);
    println!("Result 1: {}", result1);

    let cert2 = "another.org";
    let data2 = "data_payload_b";

    println!("
--- Second Run (Different Cert) ---");
    let result2 = monitor.process_record(cert2, data2);
    println!("Result 2: {}", result2);

    println!("
--- Third Run (Same Cert as First) ---");
    let result3 = monitor.process_record(cert1, "new_data_payload_ignored");
    println!("Result 3: {}", result3);
}

use std::collections::HashMap;
use std::sync::Mutex;

struct GameState {
    memo: Mutex<HashMap<(String, u32), i32>>,
}

impl GameState {
    fn new() -> Self {
        GameState {
            memo: Mutex::new(HashMap::new()),
        }
    }

    fn calculate_damage(&self, weapon_name: &str, base_attack: u32) -> i32 {
        let key = (weapon_name.to_string(), base_attack);

        { 
            let memo_guard = self.memo.lock().unwrap();
            if let Some(&result) = memo_guard.get(&key) {
                println!("Cache hit for key: {:?}", key);
                return result;
            }
        }

        let calculated_value = (base_attack as i32) * 2 - (weapon_name.len() as i32); 

        { 
            let mut memo_guard = self.memo.lock().unwrap();
            memo_guard.insert(key.clone(), calculated_value);
            println!("Cache miss and stored result for key: {:?}", key);
        }

        calculated_value
    }
}

use std::collections::HashMap;

struct CacheStore {
    memo: HashMap<String, String>,
}

impl CacheStore {
    fn new() -> Self {
        CacheStore { memo: HashMap::new() }
    }

    fn set_value(&mut self, key: String, value: String) {
        self.memo.insert(key, value);
    }

    fn get_value(&self, key: &str) -> Option<&String> {
        self.memo.get(key)
    }
}

fn calculate_expensive_result(input: i32) -> String {
    println!("Simulating expensive database query for {}", input);
    format!("Result_for_{}", input * 10)
}

fn get_cached_result(cache: &mut CacheStore, input: i32) -> String {
    let key = format!("{}", input);

    if let Some(result) = cache.get_value(&key) {
        println!("Cache hit for key: {}", &key);
        return result.clone()
    }

    let result = calculate_expensive_result(input);
    cache.set_value(key, result.clone());
    result
}

fn main() {
    let mut cache = CacheStore::new();

    println!("--- First Request ---");
    let result1 = get_cached_result(&mut cache, 42);
    println!("Final Response: {}", result1);

    println!("n--- Second Request (Cache Expected) ---");
    let result2 = get_cached_result(&mut cache, 42);
    println!("Final Response: {}", result2);

    println!("n--- Third Request (New Data) ---");
    let result3 = get_cached_result(&mut cache, 100);
    println!("Final Response: {}", result3);
}

use std::collections::HashMap;

struct JobRunner {
    memo: HashMap<String, u64>,
}

impl JobRunner {
    fn new() -> Self {
        JobRunner { memo: HashMap::new() }
    }

    fn calculate_expensive_result(&mut self, key: String) -> u64 {
        if let Some(&result) = self.memo.get(&key) {
            println!("Cache hit for {}", key);
            return result;
        }

        println!("Cache miss. Calculating result for {}", key);
        let result = key.len() as u64 * 3 + 10;
        self.memo.insert(key, result);
        result
    }
}

fn main() {
    let mut runner = JobRunner::new();

    let job_key_a = String::from("data_chunk_A");
    let job_key_b = String::from("data_chunk_B");

    let result1 = runner.calculate_expensive_result(job_key_a.clone());
    println!("Result 1: {}", result1);

    let result2 = runner.calculate_expensive_result(job_key_b.clone());
    println!("Result 2: {}", result2);

    let result3 = runner.calculate_expensive_result(job_key_a.clone());
    println!("Result 3: {}", result3);
}
